import{c as e,Q as i,j as a,m as t}from"./chunks/framework.4b-lwRvT.js";const u=JSON.parse('{"title":"项目生命周期","description":"","frontmatter":{"title":"项目生命周期"},"headers":[],"relativePath":"workflow/project-lifetime.md","filePath":"workflow/project-lifetime.md","lastUpdated":1779684191000}'),s={name:"workflow/project-lifetime.md"};function r(o,l,n,p,d,c){return i(),a("div",null,[...l[0]||(l[0]=[t(`<h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><h3 id="part-确定开发" tabindex="-1">Part：确定开发 <a class="header-anchor" href="#part-确定开发" aria-label="Permalink to &quot;Part：确定开发&quot;">​</a></h3><h4 id="step1" tabindex="-1">Step1: <a class="header-anchor" href="#step1" aria-label="Permalink to &quot;Step1:&quot;">​</a></h4><p>产品产品，需要明确好要做什么，我们要把产品做的怎么样，所以核心步骤如下</p><ul><li>明确产品功能、性能指标、外观尺寸、供电方式等</li><li>软件/硬件同步确认接口与依赖</li></ul><p>这个步骤要产出CheckList清单。</p><hr><h3 id="part-硬件" tabindex="-1">Part：硬件 <a class="header-anchor" href="#part-硬件" aria-label="Permalink to &quot;Part：硬件&quot;">​</a></h3><blockquote><p>Todo: 准备对下面的步骤进行细化和矫正，记得发 Merge Request 就好</p></blockquote><h4 id="step2-硬件原理图设计-外设接口定义" tabindex="-1"><strong>Step2. 硬件原理图设计 &amp; 外设接口定义</strong> <a class="header-anchor" href="#step2-硬件原理图设计-外设接口定义" aria-label="Permalink to &quot;**Step2. 硬件原理图设计 &amp; 外设接口定义**&quot;">​</a></h4><ul><li>完成电气架构设计</li><li>定义 MCU/SoC 引脚、通讯接口、传感器/外设连接</li><li>评审接口文档（软件与硬件共同确认）</li></ul><hr><h4 id="step3-pcb-设计与样板制作-evt-sample" tabindex="-1"><strong>Step3. PCB 设计与样板制作（EVT Sample）</strong> <a class="header-anchor" href="#step3-pcb-设计与样板制作-evt-sample" aria-label="Permalink to &quot;**Step3. PCB 设计与样板制作（EVT Sample）**&quot;">​</a></h4><ul><li>根据原理图进行 PCB layout</li><li>制作小批量样板（EVT 阶段）</li><li>进行基础电气测试</li></ul><hr><h4 id="step4-bsp-bootloader-bring-up" tabindex="-1"><strong>Step4. BSP / Bootloader Bring-up</strong> <a class="header-anchor" href="#step4-bsp-bootloader-bring-up" aria-label="Permalink to &quot;**Step4. BSP / Bootloader Bring-up**&quot;">​</a></h4><ul><li>上电验证</li><li>Bootloader 调试（U-Boot、裸机Boot、自研Boot等）</li><li>DDR/PMIC/Clock 初始化验证</li><li>基础外设点亮（GPIO、UART、I2C、SPI 等）</li></ul><hr><h3 id="part-软件" tabindex="-1">Part：软件 <a class="header-anchor" href="#part-软件" aria-label="Permalink to &quot;Part：软件&quot;">​</a></h3><p>软件开发主要做的是开发基本所用到的业务库，上层具体的APP逻辑，分离出业务层，驱动层和对接的HAL层</p><h4 id="step2-驱动开发与调试-driver-development" tabindex="-1"><strong>Step2. 驱动开发与调试（Driver Development）</strong> <a class="header-anchor" href="#step2-驱动开发与调试-driver-development" aria-label="Permalink to &quot;**Step2. 驱动开发与调试（Driver Development）**&quot;">​</a></h4><ul><li>编写并调试各外设驱动（屏幕、触摸、传感器、通信模块等）</li><li>进行中断、DMA、时序验证</li><li>输出驱动级测试报告</li></ul><hr><h4 id="step3-高层业务逻辑开发-application-service-layer" tabindex="-1"><strong>Step3. 高层业务逻辑开发（Application / Service Layer）</strong> <a class="header-anchor" href="#step3-高层业务逻辑开发-application-service-layer" aria-label="Permalink to &quot;**Step3. 高层业务逻辑开发（Application / Service Layer）**&quot;">​</a></h4><ul><li>软件架构实现（库/业务分层、CTRL/API 层）</li><li>UI/协议/业务功能实现</li><li>单元测试与模块功能测试</li></ul><hr><h4 id="step4-mock出硬件无关的软件逻辑测试" tabindex="-1">Step4. Mock出硬件无关的软件逻辑测试 <a class="header-anchor" href="#step4-mock出硬件无关的软件逻辑测试" aria-label="Permalink to &quot;Step4. Mock出硬件无关的软件逻辑测试&quot;">​</a></h4><ul><li>要求对硬件无关的逻辑代码编写Mock测试确保上层代码的可靠性</li><li>抽象和组合高可复用低开销的库组件后续进行复用（可从BetterATK中迁出分发）</li></ul><h3 id="part-联调与prerelease阶段" tabindex="-1">Part:联调与PreRelease阶段 <a class="header-anchor" href="#part-联调与prerelease阶段" aria-label="Permalink to &quot;Part:联调与PreRelease阶段&quot;">​</a></h3><hr><h4 id="step5-系统集成测试-含实机联调" tabindex="-1"><strong>Step5. 系统集成测试（含实机联调）</strong> <a class="header-anchor" href="#step5-系统集成测试-含实机联调" aria-label="Permalink to &quot;**Step5. 系统集成测试（含实机联调）**&quot;">​</a></h4><ul><li>将驱动与业务层集成</li><li>在真实硬件上进行全链路测试</li><li>功能性、稳定性、性能测试</li><li>软件与硬件同步修复问题</li></ul><hr><h4 id="step6-回归测试-长稳测试-dvt-阶段" tabindex="-1"><strong>Step6. 回归测试 &amp; 长稳测试（DVT 阶段）</strong> <a class="header-anchor" href="#step6-回归测试-长稳测试-dvt-阶段" aria-label="Permalink to &quot;**Step6. 回归测试 &amp; 长稳测试（DVT 阶段）**&quot;">​</a></h4><ul><li>大量重复测试确保更新不引入新 Bug</li><li>压测 / 老化测试（Burn-in）</li><li>温度、震动、电磁等稳定性验证（如需）</li></ul><hr><h4 id="step7-小批量试产-pvt-sample" tabindex="-1"><strong>Step7. 小批量试产（PVT Sample）</strong> <a class="header-anchor" href="#step7-小批量试产-pvt-sample" aria-label="Permalink to &quot;**Step7. 小批量试产（PVT Sample）**&quot;">​</a></h4><ul><li>小规模生产验证工艺</li><li>改善良率、生产流程、测试夹具</li><li>收集现场问题并修复</li></ul><hr><h3 id="part-release阶段" tabindex="-1">Part: Release阶段 <a class="header-anchor" href="#part-release阶段" aria-label="Permalink to &quot;Part: Release阶段&quot;">​</a></h3><h4 id="step8-量产-mp-全生命周期维护" tabindex="-1"><strong>Step8. 量产（MP） &amp; 全生命周期维护</strong> <a class="header-anchor" href="#step8-量产-mp-全生命周期维护" aria-label="Permalink to &quot;**Step8. 量产（MP） &amp; 全生命周期维护**&quot;">​</a></h4><ul><li>量产监控（良率、返修率）</li><li>软件 OTA 升级与维护</li><li>后续版本迭代、成本优化、Bug 修复</li></ul><h2 id="_1-目标与角色" tabindex="-1">1. 目标与角色 <a class="header-anchor" href="#_1-目标与角色" aria-label="Permalink to &quot;1. 目标与角色&quot;">​</a></h2><ul><li>目标：在保证代码分层清晰、可复用的前提下，建立稳定的软硬协作流程，支持频繁的实机验证与交付。</li><li>角色： <ul><li>软件负责人：负责软件架构、驱动/中间件、应用、CI、刷写与测试用例。</li><li>硬件负责人：负责原理图、PCB、器件选型、测试夹具与硬件验证。</li><li>联合责任：接口规范、集成测试、回归验证、版本发布。</li></ul></li></ul><h2 id="_2-软件分层与仓库-目录建议" tabindex="-1">2. 软件分层与仓库/目录建议 <a class="header-anchor" href="#_2-软件分层与仓库-目录建议" aria-label="Permalink to &quot;2. 软件分层与仓库/目录建议&quot;">​</a></h2><ul><li><p>分层（自底向上）：</p><ol><li>BSP / Boot（引导、启动代码）</li><li>HAL / 驱动层（GPIO, UART, I2C, SPI, ADC, PWM 等）</li><li>中间件（RTOS 抽象、文件系统、网络栈、协议库）</li><li>业务库（和具体硬件无关的业务逻辑、算法）</li><li>应用层（UI/CLI、具体产品逻辑）</li><li>tests（单元/集成/硬件回归）</li></ol></li><li><p>仓库策略：</p><ul><li><p>单仓库 monorepo（推荐小团队）或多仓（驱动/固件/工具分仓）。</p></li><li><p>示例目录（monorepo）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/project</span></span>
<span class="line"><span>  /bsp</span></span>
<span class="line"><span>  /hal</span></span>
<span class="line"><span>  /middleware</span></span>
<span class="line"><span>  /libs</span></span>
<span class="line"><span>  /app</span></span>
<span class="line"><span>  /tests</span></span>
<span class="line"><span>  /tools (flasher, scripts)</span></span>
<span class="line"><span>  /docs (HW-SW-interface.md, release-notes)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></li></ul></li></ul><h2 id="_3-git-协作与分支策略-推荐" tabindex="-1">3. Git 协作与分支策略（推荐） <a class="header-anchor" href="#_3-git-协作与分支策略-推荐" aria-label="Permalink to &quot;3. Git 协作与分支策略（推荐）&quot;">​</a></h2><ul><li><p>采用：<code>main</code>（始终可发布） + <code>develop</code>（日常集成） + feature 分支 (<code>feature/&lt;name&gt;</code>) + <code>hotfix/&lt;version&gt;</code></p></li><li><p>轻量方案（若偏短周期）：<code>main</code> + feature 分支 + 强制通过 PR 与 CI 才能合并到 <code>main</code>。</p></li><li><p>PR 要求：</p><ul><li>最少 1 次代码审核（prefer 2），自动通过 CI（编译 + 单元测试）。</li><li>PR 标题：<code>[feature|fix|chore] scope: short-description</code></li></ul></li><li><p>常用命令示例：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature/uart-driver</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;feat(hal/uart): initial uart driver&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature/uart-driver</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li></ul><h2 id="_4-pr-code-review-模板-放在-gitlab-merge-request-template-md-或-pr-描述" tabindex="-1">4. PR / Code review 模板（放在 <code>.gitlab/merge_request_template.md</code> 或 PR 描述） <a class="header-anchor" href="#_4-pr-code-review-模板-放在-gitlab-merge-request-template-md-或-pr-描述" aria-label="Permalink to &quot;4. PR / Code review 模板（放在 \`.gitlab/merge_request_template.md\` 或 PR 描述）&quot;">​</a></h2><ul><li>标题：<code>feat/bugfix: 简短说明</code></li><li>描述： <ul><li>变更概述（2-3 行）</li><li>影响范围（哪些模块/接口）</li><li>回归风险（高/中/低）与已做测试（列举）</li><li>需要硬件支持或夹具说明（若有）</li><li>测试命令 / 如何验证</li></ul></li><li>Review checklist（审查者勾选）： <ul><li>编译通过（本地/CI）</li><li>单元/集成测试通过</li><li>遵守编码规范（命名/注释）</li><li>接口文档更新（若改变）</li><li>有明确回退方案</li></ul></li></ul><h2 id="_5-ci-构建-实机测试-必备" tabindex="-1">5. CI / 构建 / 实机测试（必备） <a class="header-anchor" href="#_5-ci-构建-实机测试-必备" aria-label="Permalink to &quot;5. CI / 构建 / 实机测试（必备）&quot;">​</a></h2><ul><li>CI 做什么： <ul><li>Cross-compile（目标平台）并保存 artifact。</li><li>静态检查（clang-tidy, cppcheck）与格式化检查。</li><li>单元测试（Host 模拟 + 硬件抽象层 mock）。</li></ul></li><li>实机测试（Hardware-in-the-loop, HIL）： <ul><li>在 CI 中保留&quot;刷写 + 自动回归&quot;任务，若 CI 环境连接到测试工位（可用）： <ul><li>步骤：CI 下载固件 -&gt; 将固件刷写到指定测试板 -&gt; 通过串口/网络触发测试脚本 -&gt; 收集测试日志并上报。</li></ul></li><li>若无法自动化，建立半自动流程：自动构建 artifact + 手动刷写并运行标准测试脚本（并上传日志）。</li></ul></li><li>Artifact 管理：按语义版本 <code>vMAJOR.MINOR.PATCH</code>，文件名例如 <code>product-v1.2.0-20251207.bin</code>。</li></ul><h2 id="_6-硬件对接与约束-必须有书面接口协议" tabindex="-1">6. 硬件对接与约束（必须有书面接口协议） <a class="header-anchor" href="#_6-硬件对接与约束-必须有书面接口协议" aria-label="Permalink to &quot;6. 硬件对接与约束（必须有书面接口协议）&quot;">​</a></h2><ul><li>每次接口变更必须有 <code>HW-SW Interface Spec</code>（单文件）并放 <code>docs/</code>，内容至少包含： <ul><li>接口名称（例如：SENSOR_A_UART）</li><li>物理层：引脚、接口类型（UART/I2C/SPI/GPIO）、电压域、速率、pull 配置</li><li>时序：复位/唤醒/握手时序（简图或表格）</li><li>协议：帧格式、校验、最大数据长度、错误处理</li><li>电源与功耗约束（工作/睡眠电流）</li><li>传感器/模块型号与固件要求（若有）</li><li>测试点与测量方法（示例：如何测 Vcc、I2C 波形）</li></ul></li><li>对接流程： <ol><li>SW/ HW 共同制定 Interface Spec（在 issue 中审阅并审批）。</li><li>硬件负责人提供早期原理图/PCB /接口检测点截图。</li><li>软件负责人给出 HAL 接口 stub 与模拟器（若可行）。</li><li>首次样板 bring-up 前，软件提供最小可运行镜像（串口日志能看见启动）。</li></ol></li><li>接口版本化：对重要接口采用 <code>IF-v1.0</code> 标记，变更需增加次版本号并通知对方。</li></ul><h2 id="_7-集成与-bring-up-流程-建议步骤" tabindex="-1">7. 集成与 Bring-up 流程（建议步骤） <a class="header-anchor" href="#_7-集成与-bring-up-流程-建议步骤" aria-label="Permalink to &quot;7. 集成与 Bring-up 流程（建议步骤）&quot;">​</a></h2><ol><li>需求确认（功能 + 量产约束 + 功耗/成本）</li><li>硬件选型与原理图（硬件负责人）</li><li>初版 PCB 与样板（1st prototype）</li><li>BSP + Boot bring-up（软件创建最小镜像并确认串口日志能启动）</li><li>驱动开发（HAL -&gt; 驱动 -&gt; 中间件）</li><li>单元测试 + 模拟器测试（先在 Host 上跑可替代逻辑）</li><li>硬件接口验证（使用示波器/逻辑分析仪/测试夹具）</li><li>功能集成测试（整机）</li><li>回归测试与稳定性测试（压力测试、长时间运行）</li><li>版本冻结与 release note</li><li>小批量试产（验证制造链与测试夹具）</li><li>量产交付与维护</li></ol><h2 id="_8-硬件测试夹具与现场测试建议" tabindex="-1">8. 硬件测试夹具与现场测试建议 <a class="header-anchor" href="#_8-硬件测试夹具与现场测试建议" aria-label="Permalink to &quot;8. 硬件测试夹具与现场测试建议&quot;">​</a></h2><ul><li>每个关键板型准备一个&quot;测试夹具&quot;（JIG）或带 USB/串口的编程端口，方便快速刷写/给电/测量。夹具应支持自动复位与电流测量（便于功耗验证）。</li><li>保留 PCB 上的多个测试点（电源、时钟、I2C/SPI 核心信号），并在 <code>docs</code> 中标注。</li><li>制定&quot;开机验证清单&quot;（Boot checklist），例如：串口输出包含 <code>BSP: init ok</code>、I2C 能扫描到传感器、外设复位脚电平正确等。</li></ul><h2 id="_9-文档与交付物-最小集" tabindex="-1">9. 文档与交付物（最小集） <a class="header-anchor" href="#_9-文档与交付物-最小集" aria-label="Permalink to &quot;9. 文档与交付物（最小集）&quot;">​</a></h2><ul><li>必须文档： <ul><li><code>HW-SW Interface Spec</code>（详见上）</li><li><code>Bring-up Guide</code>（如何刷写、如何获取串口日志、常见问题）</li><li><code>Release Notes</code>（变更、已知问题）</li><li><code>Test Cases</code>（每个功能的验证步骤）</li></ul></li><li>交付物格式：Markdown + 二进制 artifact（固件） + 测试日志（按日期存档）。</li></ul><h2 id="_10-测试用例模板-简化" tabindex="-1">10. 测试用例模板（简化） <a class="header-anchor" href="#_10-测试用例模板-简化" aria-label="Permalink to &quot;10. 测试用例模板（简化）&quot;">​</a></h2><ul><li>用例名：<code>UART_loopback</code></li><li>前置条件：板上已连接串口转 USB 模块</li><li>步骤： <ol><li>刷写固件 <code>product-v1.2.0.bin</code></li><li>打开串口（115200,n,8,1）</li><li>发送 <code>ping\\n</code></li><li>期待 <code>pong\\n</code> 返回</li></ol></li><li>结果：PASS/FAIL + 日志片段</li></ul><h2 id="_11-质量控制与回退策略" tabindex="-1">11. 质量控制与回退策略 <a class="header-anchor" href="#_11-质量控制与回退策略" aria-label="Permalink to &quot;11. 质量控制与回退策略&quot;">​</a></h2><ul><li>每次合并到 <code>main</code> 都必须有 CI artifact 与 release note。</li><li>在硬件出现问题时保留上一个良好版本的固件和 PCB 版本（例如 <code>hw-v1.0</code>），以便快速回退。</li><li>对关键 flash 分区做双镜像或引导回滚机制（if possible）。</li></ul><h2 id="_12-日常协作与沟通节奏" tabindex="-1">12. 日常协作与沟通节奏 <a class="header-anchor" href="#_12-日常协作与沟通节奏" aria-label="Permalink to &quot;12. 日常协作与沟通节奏&quot;">​</a></h2><ul><li>每周短会（15分）：同步进度、阻塞与下周计划。</li><li>每次接口变更发起 issue + tag <code>hw-sw-interface</code>，并在 48 小时内评审（若紧急可加催促）。</li><li>所有关键决定写入 <code>docs/decision_log.md</code> 便于追踪。</li></ul>`,66)])])}const b=e(s,[["render",r]]);export{u as __pageData,b as default};
